ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?historical_era WHERE {
  ?operas a :Operas .
  ?operas p:Historical_Era ?historical_era .
  ?operas p:Duration ?duration_o .
}
ORDER BY DESC(?duration_o)
LIMIT 1 }
  component_2: { SELECT ?location WHERE {
  ?operas a :Operas .
  ?operas p:location ?location .
  ?operas p:Duration ?duration_o .
}
ORDER BY DESC(?duration_o)
LIMIT 1 }
  full: { SELECT ?historical_era ?location WHERE {
  ?operas a :Operas .
  ?operas p:Historical_Era ?historical_era .
  ?operas p:location ?location .
  ?operas p:Duration ?duration_o .
}
ORDER BY DESC(?duration_o)
LIMIT 1 }
}

PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?title ?historical_era WHERE {
  ?operas a :Operas .
  ?composers a :Composers .
  ?operas p:hasComposers ?composers .
  ?operas p:title ?title .
  ?operas p:Historical_Era ?historical_era .
  ?composers p:name ?name_lk .
  FILTER(REGEX(STR(?name_lk), "^.*Mozart.*$", "i"))
} }
  component_2: { SELECT ?title ?location WHERE {
  ?operas a :Operas .
  ?composers a :Composers .
  ?operas p:hasComposers ?composers .
  ?operas p:title ?title .
  ?operas p:location ?location .
  ?composers p:name ?name_lk .
  FILTER(REGEX(STR(?name_lk), "^.*Mozart.*$", "i"))
} }
  full: { SELECT ?title ?historical_era ?location WHERE {
  ?operas a :Operas .
  ?composers a :Composers .
  ?operas p:hasComposers ?composers .
  ?operas p:title ?title .
  ?operas p:Historical_Era ?historical_era .
  ?operas p:location ?location .
  ?composers p:name ?name_lk .
  FILTER(REGEX(STR(?name_lk), "^.*Mozart.*$", "i"))
} }
}
